# backlog_governance.py - incident action backlog aging and governance
from dataclasses import dataclass, field
from datetime import date, timedelta
from typing import List, Dict, Tuple
from enum import Enum


class Priority(str, Enum):
    P0 = 'P0'
    P1 = 'P1'
    P2 = 'P2'


@dataclass
class ActionItem:
    id: str
    incident_id: str
    description: str
    owner: str
    priority: Priority
    created_date: date
    due_date: date
    closed: bool = False
    deferred_count: int = 0

    @property
    def age_days(self) -> int:
        return (date.today() - self.created_date).days

    @property
    def is_overdue(self) -> bool:
        return not self.closed and date.today() > self.due_date


class BacklogGovernor:
    # Age thresholds that trigger governance flags
    THRESHOLDS: Dict[Priority, int] = {
        Priority.P0: 14,   # P0 open > 14 days = critical
        Priority.P1: 45,   # P1 open > 45 days = attention
        Priority.P2: 120,  # P2 open > 120 days = grooming
    }

    def __init__(self, items: List[ActionItem]):
        self.items = items

    def aged_items(self) -> List[Tuple[ActionItem, str]]:
        flagged = []
        for item in self.items:
            if item.closed:
                continue
            threshold = self.THRESHOLDS[item.priority]
            if item.age_days > threshold:
                severity = 'CRITICAL' if item.priority == Priority.P0 else 'ATTENTION'
                flagged.append((item, severity))
        return flagged

    def repeatedly_deferred(self, min_deferrals: int = 2) -> List[ActionItem]:
        return [
            i for i in self.items
            if not i.closed and i.deferred_count >= min_deferrals
        ]

    def governance_report(self) -> dict:
        open_items = [i for i in self.items if not i.closed]
        by_priority = {p.value: 0 for p in Priority}
        for i in open_items:
            by_priority[i.priority.value] += 1

        aged = self.aged_items()
        deferred = self.repeatedly_deferred()

        return {
            'open_count': len(open_items),
            'open_by_priority': by_priority,
            'aged_items': [
                {'id': i.id, 'age_days': i.age_days, 'severity': s, 'owner': i.owner}
                for i, s in aged
            ],
            'repeatedly_deferred': [
                {'id': i.id, 'deferrals': i.deferred_count, 'priority': i.priority.value}
                for i in deferred
            ],
            'recommendation': 'REVIEW' if (aged or deferred) else 'OK',
        }


if __name__ == '__main__':
    import json
    today = date.today()
    items = [
        ActionItem('AI-01', 'INC-0042', 'Add tool call budget guardrail',
                   'alice', Priority.P0, today - timedelta(days=18), today - timedelta(days=4)),
        ActionItem('AI-02', 'INC-0040', 'Update prompt review checklist',
                   'bob', Priority.P1, today - timedelta(days=50), today - timedelta(days=5),
                   deferred_count=2),
        ActionItem('AI-03', 'INC-0038', 'Add eval dataset diversity check',
                   'carol', Priority.P2, today - timedelta(days=30), today + timedelta(days=60)),
    ]
    governor = BacklogGovernor(items)
    report = governor.governance_report()
    print(json.dumps(report, indent=2))
